import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable, map } from 'rxjs';
import { environment } from '../../../environments/environment';
import { Role, User } from '../models';

const TOKEN_KEY = 'auth_token';
const ACCESS_KEY = 'access_token';
const USER_KEY = 'user';
const ROLE_KEY = 'role';
const AUTH_FLAG = 'isAuthenticated';
const DEMO_PASSWORD = 'demo1234';

// Backend auth response: { access_token, token, user: { id, email, role, name, level, createdAt } }
interface AuthResponse {
  access_token?: string;
  token?: string;
  user: User;
}

// Live auth service. Talks to the NestJS backend at /api/auth/* and stores the
// real JWT so the interceptor can attach it to every subsequent request.
@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;

  private _user = signal<User | null>(this.readUser());

  readonly user = this._user.asReadonly();
  readonly isLoggedIn = computed(() => !!this._user());
  readonly role = computed<Role | null>(() => this._user()?.role ?? null);
  readonly isCoach = computed(() => this._user()?.role === 'coach');

  constructor(
    private http: HttpClient,
    private router: Router,
  ) {}

  /** Verify credentials against the backend and persist the returned JWT + user. */
  login(email: string, password: string): Observable<{ user: User; token: string }> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/login`, { email, password })
      .pipe(map((res) => this.handleAuth(res)));
  }

  /** Sign up. The first account ever created becomes coach (full_auth model). */
  signup(email: string, password: string, name?: string): Observable<{ user: User; token: string }> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/register`, {
        email,
        password,
        name: name ?? email.split('@')[0],
      })
      .pipe(map((res) => this.handleAuth(res)));
  }

  /**
   * Demo Mode — bypasses the live backend so reviewers can inspect the full
   * authenticated UI (and the screenshot pipeline can capture every view).
   * Logs in as a seeded coach so all coach-only affordances are visible.
   */
  demoLogin(): void {
    const demoUser: User = {
      id: 'demo-coach',
      name: 'Demo Coach',
      email: 'coach@demo',
      role: 'coach',
      level: 'competitive',
    };
    this.persist(demoUser, 'demo-token');
    this.router.navigate(['/home']);
  }

  /** Quick role switcher — authenticates against the matching seeded demo user. */
  loginAs(role: Role): void {
    const email = role === 'coach' ? 'coach@demo' : 'rower1@demo';
    this.login(email, DEMO_PASSWORD).subscribe({
      next: () => this.router.navigate(['/home']),
      error: () => this.router.navigate(['/login']),
    });
  }

  logout(): void {
    [TOKEN_KEY, ACCESS_KEY, USER_KEY, ROLE_KEY, AUTH_FLAG, 'token'].forEach((k) =>
      localStorage.removeItem(k),
    );
    this._user.set(null);
    this.router.navigate(['/login']);
  }

  hasRole(...roles: Role[]): boolean {
    const r = this.role();
    return !!r && roles.includes(r);
  }

  /**
   * Fetch the live authenticated user from the backend and refresh local state.
   * Used by the app shell so the header/nav reflect the real server-side user.
   */
  refreshCurrentUser(): Observable<User> {
    return this.http.get<User>(`${this.apiUrl}/users/me`).pipe(
      map((user) => {
        const token = localStorage.getItem(TOKEN_KEY) ?? '';
        this.persist(user, token);
        return user;
      }),
    );
  }

  private handleAuth(res: AuthResponse): { user: User; token: string } {
    const token = res.access_token ?? res.token ?? '';
    this.persist(res.user, token);
    return { user: res.user, token };
  }

  private persist(user: User, token: string): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(ACCESS_KEY, token);
    localStorage.setItem('token', token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    localStorage.setItem(ROLE_KEY, user.role);
    localStorage.setItem(AUTH_FLAG, 'true');
    this._user.set(user);
  }

  private readUser(): User | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as User) : null;
    } catch {
      return null;
    }
  }
}
